// Filter patients whose follow-up is tomorrow, status is pending, and have not been over-messaged.
const items = $input.all();
const tz = $env.TIMEZONE || 'Asia/Kolkata';
const maxMessages = parseInt($env.MAX_MESSAGE_COUNT) || 5;
const minHours = parseInt($env.MIN_HOURS_BETWEEN_MESSAGES) || 23;
const now = new Date();
const tomorrow = new Date(now);
tomorrow.setDate(tomorrow.getDate() + 1);
const tomorrowStr = tomorrow.toLocaleDateString('en-CA', { timeZone: tz });
const filtered = items.filter(item => {
  const p = item.json;
  const fuDate = p.follow_up_date ? new Date(p.follow_up_date).toLocaleDateString('en-CA', { timeZone: tz }) : null;
  if (!fuDate || fuDate !== tomorrowStr) return false;
  if (p.status && p.status !== 'pending') return false;
  if ((parseInt(p.message_count) || 0) >= maxMessages) return false;
  if (!p.phone || !/^\+[1-9]\d{6,14}$/.test(p.phone)) return false;
  if (p.last_message_sent) {
    const hoursSince = (now - new Date(p.last_message_sent)) / (1000 * 60 * 60);
    if (hoursSince < minHours) return false;
  }
  return true;
});
if (filtered.length === 0) return [{ json: { _skip: true, reason: 'No patients to message today', tomorrowStr } }];
return filtered.map(item => {
  const p = item.json;
  const name = p.name || 'there';
  const doctor = p.doctor_name || $env.DEFAULT_DOCTOR_NAME || 'your doctor';
  const clinic = p.clinic_name || $env.DEFAULT_CLINIC_NAME || 'our clinic';
  const followUpDisplay = new Date(p.follow_up_date).toLocaleDateString('en-IN', { timeZone: tz, weekday: 'short', day: '2-digit', month: 'short' });
  const contentSid = $env.TWILIO_CONTENT_FOLLOWUP_REMINDER_ADVANCE || $env.TWILIO_CONTENT_FOLLOWUP_CONFIRMATION || $env.TWILIO_CONTENT_FOLLOW_UP_REMINDER || '';
  const contentVars = { '1': name, '2': doctor, '3': followUpDisplay };
  const messageBody = `Hi ${name}, your follow-up with ${doctor} is coming up on ${followUpDisplay}. Please confirm using the button below.`;
  return { json: { ...p, _clinic_id: p.clinic_id, _workflow: 'workflow-1-followup-reminder', _message_type: 'followup_reminder_advance', _scheduled_date: tomorrowStr, _to_phone: 'whatsapp:' + p.phone, _name: name, _doctor_name: doctor, _clinic_name: clinic, _content_sid: contentSid, _content_variables: JSON.stringify(contentVars), _message_body: messageBody } };
});
